var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"뭐냐! 저 공세는 대체 뭐냔 말이다!","JPN":"何なんだ！　あの猛烈な勢いは何なのだ！","ENG":"What? Why are they mounting an offensive like that?","TWN":"搞什麼！這個攻勢是怎麼回事！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"곧 침식체로 변할 폐품들 주제에 왜 겁도 없이 달려드는 거지?!","JPN":"もうじき侵食体に変異するだろう廃棄品どものくせに、\\n何故こうも果敢に襲いかかってくるのだ！？","ENG":"They're nothing but scraps doomed to become C.O.s soon. Where did they find the gall to come attacking?","TWN":"他們明明馬上就要變成侵蝕體了，難道他們都不害怕的嗎？！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"어차피 침식되어 가는 몸인데 뭐가 두렵겠나, 도플갱어!","JPN":"どうせ侵食しかかってる身体だ。\\n今更怖いものなんてあるもんかよ、ドッペルゲンガーめ！","ENG":"What have we got to fear when we're all good as dead, Doppelganger?","TWN":"反正都要變成侵蝕體了，還有什麼好害的，二重身！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_TOUCH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"오히려 다쳐도 아프지 않으니 잘됐군!","JPN":"怪我をしても痛くねえし、むしろ便利になったもんだぜ！","ENG":"If anything, the Corruption has numbed our pain! It's the perfect time for fighting!","TWN":"受傷也感覺不到痛，這反倒是件好事！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"이봐, 발레리. 혹시 내가 침식체가 돼서 정신줄 놓으면 민폐 끼치기 전에 알아서 끝내 달라고.","JPN":"おい、ヴァレリー。もし俺が侵食体になって頭がイカれちまったら、\\nみんなに迷惑かける前にお前が終わらせてくれよな。","ENG":"Hey, Valeriy. If I start losing my mind as a C.O., put me out of my misery before I do anything stupid.","TWN":"喂，瓦萊里，萬一我變成侵蝕體失去自我的話，在我造成其他人的麻煩前，你一定要馬上殺了我。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"내가 할 소리야, 예고르. 가능하면 깔끔하게 부탁하지.","JPN":"俺からも頼むぜ、イェゴール。なるべくサクッと逝かせてくれ。","ENG":"Likewise, Yegor. Try to make it as clean and quick as possible.","TWN":"這是我要說的話，伊高爾，請你乾脆地了結我。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"다들 조용. 찬물도 위아래가 있다는 거 잊었어?","JPN":"まあ、生意気ですこと。上官を差し置いて先に逝こうっていうの？","ENG":"Tut, tut, everyone. Don't you forget that I outrank y'all.","TWN":"全都安靜，你們是不知道長幼有序嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"나보다 먼저 침식체가 되는 애는 가만 안 둬. 알겠지?","JPN":"私より先に侵食体になるような子は、ただでは済まないからね。\\n以後気をつけなさい！","ENG":"None of you better beat me to becoming a C.O. Alright?","TWN":"我不會放過那些比我先變成侵蝕體的傢伙，知道了嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"지독한 것들......! 죽기 전에 마지막 발악이라도 할 셈인가......!","JPN":"忌々しい奴らめ……！　最期の悪足掻きのつもりか……！","ENG":"You relentless fools! So you want to throw one last tantrum before you die?","TWN":"該死的東西……！都要死了，還要做最後的掙扎嗎……！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"......그러길래 내가 싸우지 말고 기다리자고 했잖아.","JPN":"……だから戦わないで待とうって言ったのに。","ENG":"I told you we should've waited instead of fighting.","TWN":"……所以我才說過不要正面交鋒，而是要靜靜等待啊。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"알렉스, 내 앞에서 또 그딴 소리를 해?","JPN":"アレックス、貴様はまだそんなことが言えるのか？","ENG":"You dare bring that up to me again, Alex?","TWN":"雅蕾克絲，妳又在我面前說這些嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"무능한 네놈들이 포격만 제대로 맞췄어도 이럴 일은 없었어!","JPN":"無能な貴様たちが砲撃さえ外していなければ、こんなザマにはなっていない！","ENG":"If only you incompetent fools had landed your shots, it wouldn't have come to this!","TWN":"如果不是妳這個無能的笨蛋打歪，根本不會發生這種事！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"하는 수 없지. <color=#ffd34c>그걸</color> 동원해.","JPN":"仕方ない。<color=#ffd34c>あれ</color>を出すぞ。","ENG":"This leaves us no choice. Get <color=#ffd34c>it</color> ready.","TWN":"沒辦法了。用<color=#ffd34c>那個</color>吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"놈들과 방주를 싸잡아 박살내 주지!","JPN":"奴らと箱舟をまとめて潰してやる！","ENG":"We'll crush them and the Ark together!","TWN":"我要把他們連同方舟一起粉碎！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"크로노스를?","JPN":"クロノスを使うの？","ENG":"You mean Chronos?","TWN":"妳是說克羅諾斯？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"무리야. 그 녀석을 움직이려고 애들 수십 명을 동력원으로 썼는데도 꿈쩍 안 했잖아.","JPN":"無理よ。あいつを動かそうと子どもたちを何十人も\\n動力源として放り込んだのに、びくともしなかったじゃない。","ENG":"I'm not sure we can. We burnt up dozens of our guys to power that thing, but it wouldn't budge.","TWN":"不行，為了啟動那東西，我們曾把數十個孩子當作動力源去驅動，但最後還是失敗了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"}}}}]`);export{e as default};